  char buf[4096];
  int len = fread(buf, 1, sizeof(buf) - 1, stdin);
  if (len < 0) return 0;
  buf[len] = '\0';
  char clean[4096];
  int k = 0;
  for (int i = 0; i < len; i++) {
    unsigned char ch = (unsigned char)buf[i];
    if (isalnum(ch)) clean[k++] = (char)tolower(ch);
  }
  int l = 0, r = k - 1;
  int ok = 1;
  while (l < r) {
    if (clean[l] != clean[r]) { ok = 0; break; }
    l++;
    r--;
  }
  printf(ok ? "true\n" : "false\n");
  return 0;
}

